import (
	"fmt"
	"os"
	"sort"
	"strings"
)

func main() {
	if len(os.Args) < 2 || os.Args[1] == "" {
		return
	}
	pairs := strings.Split(os.Args[1], "&")
	type kv struct {
		key, value string
	}
	var kvs []kv
	for _, p := range pairs {
		if p == "" {
			continue
		}
		idx := strings.Index(p, "=")
		if idx == -1 {
			kvs = append(kvs, kv{p, ""})
		} else {
			kvs = append(kvs, kv{p[:idx], p[idx+1:]})
		}
	}
	sort.Slice(kvs, func(i, j int) bool {
		return kvs[i].key < kvs[j].key
	})
	for _, x := range kvs {
		fmt.Println(x.key + "=" + x.value)
	}
}

import sys

def rpn(expr):
    stack = []
    for token in expr.split():
        if token in '+-*/':
            b = stack.pop()
            a = stack.pop()
            if token == '+':
                stack.append(a + b)
            elif token == '-':
                stack.append(a - b)
            elif token == '*':
                stack.append(a * b)
            elif token == '/':
                stack.append(int(a / b))
        else:
            stack.append(int(token))
    return stack[0]

