import (
	"fmt"
	"os"
	"strconv"
)

func main() {
	mode := os.Args[1]
	shift, _ := strconv.Atoi(os.Args[2])
	message := os.Args[3]

	if mode == "decode" {
		shift = -shift
	}

	shift = ((shift % 26) + 26) % 26

	result := make([]byte, len(message))
	for i := 0; i < len(message); i++ {
		c := message[i]
		switch {
		case c >= 'a' && c <= 'z':
			result[i] = byte((int(c-'a')+shift)%26) + 'a'
		case c >= 'A' && c <= 'Z':
			result[i] = byte((int(c-'A')+shift)%26) + 'A'
		default:
			result[i] = c
		}
	}

	fmt.Println(string(result))
}
